class Solution:
    def smallestNumber(self, num: int) -> int:
        if num == 0:
            return 0
        sign = -1 if num < 0 else 1
        counts = [0] * 10
        for ch in str(abs(num)):
            counts[int(ch)] += 1
        digits = []
        if sign == 1:
            first = next(d for d in range(1, 10) if counts[d] > 0)
            counts[first] -= 1
            digits.append(str(first))
            for d in range(10):
                digits.extend([str(d)] * counts[d])
        else:
            for d in range(9, -1, -1):
                digits.extend([str(d)] * counts[d])
        return sign * int(''.join(digits))

