class Solution:
    def smallestNumber(self, num: int) -> int:
        if num == 0:
            return 0
        sign = -1 if num < 0 else 1
        digits = sorted(str(abs(num)))
        if sign == 1:
            if digits[0] == '0':
                for i in range(1, len(digits)):
                    if digits[i] != '0':
                        digits[0], digits[i] = digits[i], digits[0]
                        break
        else:
            digits.reverse()
        return sign * int(''.join(digits))

