var smallestNumber = function(num) {
    if (num === 0) return 0;
    const sign = num < 0 ? -1 : 1;
    const digits = String(Math.abs(num)).split('').sort();
    if (sign === 1) {
        if (digits[0] === '0') {
            for (let i = 1; i < digits.length; i++) {
                if (digits[i] !== '0') {
                    const t = digits[0];
                    digits[0] = digits[i];
                    digits[i] = t;
                    break;
                }
            }
        }
    } else {
        digits.reverse();
    }
    return sign * parseInt(digits.join(''), 10);
};
